class Piece:
    RED = 'R'
    BLACK = 'B'
    KING = 'K'

    def __init__(self, color):
        self.color = color
        self.king = False

    def __repr__(self):
        if self.king:
            return f"{self.color}K"
        return self.color

class Board:
    SIZE = 8
    EMPTY = None

    def __init__(self):
        self._board = [[self.EMPTY for _ in range(self.SIZE)] for _ in range(self.SIZE)]
        self.initialize_board()

    def initialize_board(self):
        colors = [Piece.RED, Piece.BLACK]
        for color in colors:
            direction = 1 if color == Piece.RED else -1
            for row in range(3 + direction, 5 + direction, direction):
                for col in range((row + direction) % 2, self.SIZE, 2):
                    self._board[row][col] = Piece(color)

    def print_board(self):
        for row in range(self.SIZE):
            for col in range(self.SIZE):
                if self._board[row][col]:
                    print(f"{self._board[row][col]}", end=" ")
                else:
                    print(".", end=" ")
            print()

    def is_valid_move(self, from_row, from_col, to_row, to_col):
        # Check bounds and piece existence
        if (from_row < 0 or from_row >= self.SIZE or
            from_col < 0 or from_col >= self.SIZE or
            to_row < 0 or to_row >= self.SIZE or
            to_col < 0 or to_col >= self.SIZE or
            self._board[from_row][from_col] is None):
            return False

        piece = self._board[from_row][from_col]
        # Check move direction and distance
        if not ((to_row - from_row, to_col - from_col) in [(-1, -1), (-1, 1), (1, -1), (1, 1)]):
            return False

        if piece.color == Piece.RED:
            direction = -1
        else:
            direction = 1

        if abs(to_row - from_row) > 2:
            return False

        # Check for capture and jump over opponent's piece
        if (abs(to_row - from_row) == 2):
            mid_piece = self._board[(from_row + to_row) // 2][(from_col + to_col) // 2]
            if mid_piece is None or mid_piece.color == piece.color:
                return False

        return True

    def make_move(self, from_row, from_col, to_row, to_col):
        piece = self._board[from_row][from_col]
        self._board[from_row][from_col] = self.EMPTY
        if abs(to_row - from_row) == 2:
            mid_piece = self._board[(from_row + to_row) // 2][(from_col + to_col) // 2]
            self._board[(from_row + to_row) // 2][(from_col + to_col) // 2] = self.EMPTY
        self._board[to_row][to_col] = piece

    def king_piece(self, row, col):
        if (row == 0 and self._board[row][col].color == Piece.RED) or \
           (row == self.SIZE - 1 and self._board[row][col].color == Piece.BLACK):
            self._board[row][col] = Piece(self._board[row][col].color, king=True)

    def get_valid_moves(self, color):
        moves = []
        for row in range(self.SIZE):
            for col in range(self.SIZE):
                if self._board[row][col] and self._board[row][col].color == color:
                    for dr, dc in [(-1, -1), (-1, 1), (1, -1), (1, 1)]:
                        to_row, to_col = row + dr, col + dc
                        if self.is_valid_move(row, col, to_row, to_col):
                            moves.append((row, col, to_row, to_col))
        return moves
