        players[current_player_index].make_move(board)

        # Check for win or draw
        if not board.get_valid_moves(players[current_player_index % 2]):
            winner = (current_player_index + 1) % 2 + 1
            print(f"Player {winner} wins!")
            break

if __name__ == "__main__":
